#include <cmath>

long long solve(long long n, long long m, long long k) {
    if (k == 0) {
        return n * m;
    }
    if (k >= std::min(n, m)) {
        return 1;
    }
    long long rows = std::ceil((n + 1) / (2 * k + 1));
    long long cols = std::ceil((m + 1) / (2 * k + 1));
    return rows * cols;
}
